package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void testNullValue_noDeferredName_serializesNull() throws IOException {
    // deferredName == null, serializeNulls true by default
    jsonWriter.nullValue();
    assertEquals("null", stringWriter.toString());
  }

  @Test
  public void testNullValue_deferredNameNullsTrue_writesDeferredNameAndNull() throws IOException, Exception {
    // Set deferredName to non-null and serializeNulls true
    setField(jsonWriter, "deferredName", "key");
    jsonWriter.setSerializeNulls(true);

    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to spy on private writeDeferredName method call count
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    // We cannot verify private method call directly with Mockito, so we wrap the method to count calls
    InvocationCounter counter = new InvocationCounter();
    doAnswer(invocation -> {
      counter.increment();
      return invocation.callRealMethod();
    }).when(spyWriter).nullValue(); // We will call nullValue on spy, but writeDeferredName is private, so we can't mock it directly

    // Instead, call nullValue on spyWriter normally
    spyWriter.nullValue();

    // Use reflection to check deferredName is null after call
    assertNull(getField(spyWriter, "deferredName"));

    // The output should contain "null"
    String output = stringWriter.toString();
    assertTrue(output.contains("null"));
  }

  @Test
  public void testNullValue_deferredNameNullsFalse_skipsNameAndWritesNull() throws IOException {
    setField(jsonWriter, "deferredName", "key");
    jsonWriter.setSerializeNulls(false);

    JsonWriter spyWriter = spy(jsonWriter);

    spyWriter.nullValue();

    // deferredName should be null after skipping
    assertNull(getField(spyWriter, "deferredName"));

    // Output should contain only "null"
    assertEquals("null", stringWriter.toString());
  }

  @Test
  public void testNullValue_beforeValueCalled() throws IOException, Exception {
    // Spy on jsonWriter to verify private beforeValue() is called
    JsonWriter spyWriter = spy(jsonWriter);

    // Call nullValue
    spyWriter.nullValue();

    // The output should be "null"
    assertEquals("null", stringWriter.toString());
  }

  // Utility method to set private fields via reflection
  private static void setField(Object target, String fieldName, Object value) {
    try {
      Field field = target.getClass().getDeclaredField(fieldName);
      field.setAccessible(true);
      field.set(target, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Utility method to get private field value via reflection
  private static Object getField(Object target, String fieldName) {
    try {
      Field field = target.getClass().getDeclaredField(fieldName);
      field.setAccessible(true);
      return field.get(target);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Helper class to count invocations
  private static class InvocationCounter {
    private int count = 0;
    void increment() {
      count++;
    }
    int getCount() {
      return count;
    }
  }
}
